mapper.sql:
where y.deleted = 0
  and y.youth_type = #{youthType}

    and y.name like concat('%', #{query.name}, '%')


    and y.gender = #{query.gender}


    and y.ethnicity = #{query.ethnicity}


    and date_format(y.birth_date, '%Y-%m') = #{query.birthDate}


    and y.recruitment_year = #{query.recruitmentYear}


    and y.political_status = #{query.politicalStatus}


    and y.education_level = #{query.educationLevel}


    and y.education_level in

        #{educationCode}



    and y.degree_code = #{query.degreeCode}


    and y.native_county_code = #{query.nativeCountyCode}


    and y.native_city_code = #{query.nativeCityCode}


    and y.native_province_code = #{query.nativeProvinceCode}


    and y.residence_county_code = #{query.residenceCountyCode}


    and y.residence_city_code = #{query.residenceCityCode}


    and y.residence_province_code = #{query.residenceProvinceCode}


    and y.school_county_code = #{query.schoolCountyCode}


    and y.school_city_code = #{query.schoolCityCode}


    and y.school_province_code = #{query.schoolProvinceCode}


    and y.school_code = #{query.schoolCode}


    and y.major_code = #{query.majorCode}


    and y.major_code in

        #{majorCode}



    and y.major_category = #{query.majorCategory}


    and s.category_dict_item_id in

        #{schoolCategoryId}



    and y.phone like concat('%', #{query.phone}, '%')

mapper.select:
select y.id, y.youth_type, y.name, coalesce(gd.dict_label, y.gender) as gender, y.birth_date, coalesce(eth.dict_label, y.ethnicity) as ethnicity, coalesce(ps.dict_label, y.political_status) as political_status, y.native_province_code, y.native_city_code, y.native_county_code, concat_ws('-', np.region_name, nc.region_name, nct.region_name) as native_place_name, y.education_level, coalesce(ed.dict_label, y.education_level) as education_level_name, y.degree_code, coalesce(dd.dict_label, y.degree_code) as degree_name, y.school_code, coalesce(s.school_name, y.school_name) as school_name, y.school_province_code, y.school_city_code, y.school_county_code, concat_ws('-', sp.region_name, sc.region_name, sct.region_name) as school_region_name, y.major_code, coalesce(m.major_name, y.major) as major, coalesce(mc.dict_label, mcd.dict_label, y.major_category) as major_category, y.recruitment_year, y.graduation_date, y.employment_direction, y.phone, y.residence_province_code, y.residence_city_code, y.residence_county_code, concat_ws('-', rp.region_name, rc.region_name, rct.region_name) as current_residence_name, y.employment_status, y.current_job, y.employment_company, y.entrepreneurship_status, y.entrepreneurship_project, y.entrepreneurship_demand, y.sort_order, y.remarks, y.create_time from youth_info y left join sys_dict_item gd on gd.dict_type = 'gender' and gd.dict_value = y.gender and gd.enabled = 1 left join sys_dict_item eth on eth.dict_type = 'ethnicity' and eth.dict_value = y.ethnicity and eth.enabled = 1 left join sys_dict_item ps on ps.dict_type = 'political_status' and ps.dict_value = y.political_status and ps.enabled = 1 left join sys_dict_item ed on ed.dict_type = 'education_level' and ed.dict_value = y.education_level and ed.enabled = 1 left join sys_dict_item dd on dd.dict_type = 'degree' and dd.dict_value = y.degree_code and dd.enabled = 1 left join sys_school s on s.school_code = y.school_code left join sys_major_catalog m on m.major_code = y.major_code left join sys_dict_item mc on mc.id = m.category_dict_item_id and mc.enabled = 1 left join sys_dict_item mcd on mcd.dict_type = 'major_category' and mcd.dict_value = y.major_category and mcd.enabled = 1 left join sys_region np on np.region_code = y.native_province_code left join sys_region nc on nc.region_code = y.native_city_code left join sys_region nct on nct.region_code = y.native_county_code left join sys_region sp on sp.region_code = y.school_province_code left join sys_region sc on sc.region_code = y.school_city_code left join sys_region sct on sct.region_code = y.school_county_code left join sys_region rp on rp.region_code = y.residence_province_code left join sys_region rc on rc.region_code = y.residence_city_code left join sys_region rct on rct.region_code = y.residence_county_code
order by case when y.sort_order is null then 1 else 0 end, y.sort_order asc, y.id desc
limit #{query.offset}, #{query.safePageSize}

mapper.update:
update youth_info
set deleted = 1,
    update_by = #{updateBy}
where id = #{id}
  and deleted = 0

update youth_info
set deleted = 1,
    update_by = #{updateBy}
where youth_type = #{youthType}
  and deleted = 0
  and id in

    #{id}

mapper.select:
select count(*)
from youth_info
where deleted = 0
  and youth_type = #{youthType}
  and name = #{name}
  and phone = #{phone}
